BEGIN TRANSACTION;
DROP TABLE IF EXISTS "billing_records";
CREATE TABLE billing_records (
	id INTEGER NOT NULL, 
	date VARCHAR(20) NOT NULL, 
	time VARCHAR(20) NOT NULL, 
	is_guest BOOLEAN, 
	is_support_staff BOOLEAN, 
	customer JSON NOT NULL, 
	items JSON NOT NULL, 
	total_items INTEGER NOT NULL, 
	total_amount FLOAT NOT NULL, 
	pricing_type VARCHAR(20), 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), created_by VARCHAR(50) DEFAULT "admin", 
	PRIMARY KEY (id)
);
DROP TABLE IF EXISTS "employees";
CREATE TABLE employees (
	id INTEGER NOT NULL, 
	employee_id VARCHAR(50) NOT NULL, 
	employee_name VARCHAR(255) NOT NULL, 
	company_name VARCHAR(255), 
	entity VARCHAR(255), 
	mobile_number VARCHAR(20), 
	location VARCHAR(255), 
	qr_code TEXT, 
	created_by VARCHAR(50) NOT NULL, 
	created_date VARCHAR(20) NOT NULL, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
DROP TABLE IF EXISTS "guests";
CREATE TABLE guests (
	id INTEGER NOT NULL, 
	name VARCHAR(255) NOT NULL, 
	company_name VARCHAR(255) NOT NULL, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
DROP TABLE IF EXISTS "price_master";
CREATE TABLE price_master (
	id INTEGER NOT NULL, 
	employee_breakfast FLOAT NOT NULL, 
	employee_lunch FLOAT NOT NULL, 
	company_breakfast FLOAT NOT NULL, 
	company_lunch FLOAT NOT NULL, 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
DROP TABLE IF EXISTS "support_staff";
CREATE TABLE support_staff (
	id INTEGER NOT NULL, 
	staff_id VARCHAR(50) NOT NULL, 
	name VARCHAR(255) NOT NULL, 
	designation VARCHAR(100), 
	company_name VARCHAR(255), 
	biometric_data TEXT, 
	created_by VARCHAR(50) NOT NULL, 
	created_date VARCHAR(20) NOT NULL, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
DROP TABLE IF EXISTS "users";
CREATE TABLE users (
	id INTEGER NOT NULL, 
	username VARCHAR(50) NOT NULL, 
	hashed_password VARCHAR(255) NOT NULL, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
DROP INDEX IF EXISTS "ix_billing_records_date";
CREATE INDEX ix_billing_records_date ON billing_records (date);
DROP INDEX IF EXISTS "ix_billing_records_id";
CREATE INDEX ix_billing_records_id ON billing_records (id);
DROP INDEX IF EXISTS "ix_employees_employee_id";
CREATE UNIQUE INDEX ix_employees_employee_id ON employees (employee_id);
DROP INDEX IF EXISTS "ix_employees_id";
CREATE INDEX ix_employees_id ON employees (id);
DROP INDEX IF EXISTS "ix_guests_id";
CREATE INDEX ix_guests_id ON guests (id);
DROP INDEX IF EXISTS "ix_price_master_id";
CREATE INDEX ix_price_master_id ON price_master (id);
DROP INDEX IF EXISTS "ix_support_staff_id";
CREATE INDEX ix_support_staff_id ON support_staff (id);
DROP INDEX IF EXISTS "ix_support_staff_staff_id";
CREATE UNIQUE INDEX ix_support_staff_staff_id ON support_staff (staff_id);
DROP INDEX IF EXISTS "ix_users_id";
CREATE INDEX ix_users_id ON users (id);
DROP INDEX IF EXISTS "ix_users_username";
CREATE UNIQUE INDEX ix_users_username ON users (username);
COMMIT;
